import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";

function OfferLetter() {
  const { applicationId } = useParams();
  const [application, setApplication] = useState(null);

  useEffect(() => {
    const apps =
      JSON.parse(localStorage.getItem("applications")) || [];

    const found = apps.find(
      a => String(a.id) === String(applicationId)
    );

    setApplication(found);
  }, [applicationId]);

  if (!application) {
    return <p>Loading application...</p>;
  }

  return (
    <div style={{ marginTop: "25px", maxWidth: "600px" }}>
      <h2>Generate Offer Letter</h2>

      {/* Candidate Details */}
      <p><b>Name:</b> {application.employeeName}</p>
      <p><b>Email:</b> {application.email}</p>
      <p><b>Job Title:</b> {application.jobTitle}</p>

      <hr />

      {/* OFFER DETAILS FORM */}
      <h3>Offer Details</h3>

      <label>Offered Salary</label>
      <input
        type="text"
        placeholder="Eg: 6 LPA"
        style={{ width: "100%", marginBottom: "12px" }}
      />

      <label>Date of Joining</label>
      <input
        type="date"
        style={{ width: "100%", marginBottom: "12px" }}
      />

      <label>Work Location</label>
      <input
        type="text"
        placeholder="Eg: Hyderabad"
        style={{ width: "100%", marginBottom: "12px" }}
      />

      <label>Reporting Manager</label>
      <input
        type="text"
        placeholder="Manager Name"
        style={{ width: "100%", marginBottom: "12px" }}
      />

      <button
        style={{
          marginTop: "15px",
          background: "#16a34a",
          color: "white",
          padding: "10px 16px",
          border: "none",
          borderRadius: "6px",
          cursor: "pointer",
        }}
      >
        Generate Offer (UI Only)
      </button>
    </div>
  );
}

export default OfferLetter;
